#include<stdio.h>
#include<stdlib.h>
#include<string.h>

int main()
{
    char s[100];
    scanf("%s",s);




    int l = strlen(s);
    int len = 0;

    for(int i = 0; i<l; i++)
    {
        for(int j = i+1; j<l; j++)
        {
            int n = 0;
            while(s[i+n] == s[j+n])
                n++;
            if(n>len)
                len = n;
        }
    }

    printf("%d\n",len);

    return 0;
}

